import type { ProjectMetadata } from "@/lib/projects/types";

export const metadata: ProjectMetadata = {
  slug: "hivemind",
  code: "HVM",
  title: "Hivemind",
  tagline: "Strategic analytical software.",
  status: "in-progress",
  framing:
    "Hivemind decomposes strategy problems into evaluable hypotheses with weighted evidence and probabilistic aggregation. The output is a structured brief, not a chat transcript. The bet is that decision-grade analysis benefits from explicit structure rather than freeform prose.",
  externalLinks: [
    { label: "hivemind.ai", href: "https://hivemind.ai" },
    { label: "app.hivemind.ai", href: "https://app.hivemind.ai" },
  ],
  seedQuestion: "How does Hivemind weigh evidence across hypotheses?",
};

export default metadata;

// TODO(michael): rewrite in your voice
const thesis = {
  thesis:
    "Hivemind is strategic analytical software for operators who must reason under uncertainty.",
  mechanism:
    "It decomposes strategy questions into evaluable hypotheses, attaches weighted evidence, and aggregates probabilistic posteriors into a structured brief.",
  moat:
    "The graph of hypotheses, evidence, and counterfactuals compounds with use. The longer an operator works in Hivemind, the harder the work is to redo elsewhere.",
};
export default thesis;

