1	// Toy argument fixtures for the Layer Scoring Lab.
2	// Per CE2 §2 (layer weights) and §4 (fusion + anti-gaming).
3	// All scores precomputed; no runtime ML.
4	
5	export type PropositionType = "claim" | "premise" | "evidence" | "qualifier";
6	export type RelationType = "supports" | "attacks" | "qualifies";
7	
8	export interface Proposition {
9	  id: string;
10	  text: string;
11	  type: PropositionType;
12	  importance: number; // post-adjustment, [0,1]
13	}
14	
15	export interface Relation {
16	  sourceId: string;
17	  targetId: string;
18	  relationType: RelationType;
19	  strength: number; // [0,1]
20	}
21	
22	export type AntiGamingKey =
23	  | "AG_TEMPLATE_OVERLAP"
24	  | "AG_PRIOR_CORPUS_ECHO"
25	  | "AG_CONTRADICTION_DENIAL"
26	  | "AG_REPETITIVE_FILLER"
27	  | "AG_FLUENCY_WITHOUT_CONTENT";
28	
29	export const AG_WEIGHTS: Record<AntiGamingKey, number> = {
30	  AG_TEMPLATE_OVERLAP: 0.30,
31	  AG_PRIOR_CORPUS_ECHO: 0.25,
32	  AG_CONTRADICTION_DENIAL: 0.25,
33	  AG_REPETITIVE_FILLER: 0.20,
34	  AG_FLUENCY_WITHOUT_CONTENT: 0.15,
35	};
36	
37	export const LAYER_WEIGHTS = {
38	  s1: 0.30,
39	  s2: 0.20,
40	  s3: 0.20,
41	  s4: 0.15,
42	  s5: 0.15,
43	} as const;
44	
45	export interface S1Details {
46	  pairsChecked: number;
47	  pairsFlagged: number;
48	  topPairs: Array<{ i: string; j: string; prob: number }>;
49	  backend: "deberta-v3" | "heuristic";
50	  wcs: number;
51	}
52	export interface S2Details {
53	  groundedExtensionSize: number;
54	  totalArguments: number;
55	  fixedPointIterations: number;
56	  cycleCount: number;
57	  attackDensity: number;
58	  supportDensity: number;
59	  maxSupportDepth: number;
60	}
61	export interface S3Details {
62	  embedder: "sbert-mpnet" | "tfidf";
63	  pairCount: number;
64	  meanCosine: number;
65	  suspiciousFraction: number;
66	  hoyerMean: number;
67	  dampenedBy: number;
68	}
69	export interface S4Details {
70	  lJoint: number;
71	  lSum: number;
72	  ratio: number;
73	  s4Raw: number;
74	  lengthAdjustment: number;
75	}
76	export interface S5Details {
77	  connectivityKappa: number;
78	  isolationPenalty: number;
79	  circularityPenalty: number;
80	  depthBonus: number;
81	  longestChain: number;
82	}
83	
84	export interface LayerResult<D> {
85	  score: number;
86	  weight: number;
87	  details: D;
88	  warnings?: string[];
89	}
90	
91	export interface LayerScores {
92	  s1: LayerResult<S1Details>;
93	  s2: LayerResult<S2Details>;
94	  s3: LayerResult<S3Details>;
95	  s4: LayerResult<S4Details>;
96	  s5: LayerResult<S5Details>;
97	}
98	
99	export interface FusionResult {
100	  s3BeforeFusion: number;
101	  s3AfterFusion: number;
102	  fusionCoefficient: number;
103	  trigger: "none" | "s1-high-confidence";
104	}
105	
106	export interface AntiGamingResult {
107	  enabled: boolean;
108	  signals: Record<AntiGamingKey, number>;
109	  rawSum: number;
110	  score: number;
111	  floor: "clamped" | "unclamped";
112	  floorExpression: "clamp(1.0 - Σ w·s, 0.0, 1.0)";
113	}
114	
115	export interface ArgumentFixture {
116	  id: string;
117	  label: string;
118	  topic: string;
119	  propositions: Proposition[];
120	  relations: Relation[];
121	  layerScores: LayerScores;
122	  fusion: FusionResult;
123	  antiGaming: AntiGamingResult;
124	  composite: number;
125	  compositeBeforeFusion: number;
126	  citation: "CE2 §2-§4";
127	}
128	
129	function ag(signals: Record<AntiGamingKey, number>): AntiGamingResult {
130	  let rawSum = 0;
131	  for (const k of Object.keys(signals) as AntiGamingKey[]) {
132	    rawSum += AG_WEIGHTS[k] * signals[k];
133	  }
134	  const score = Math.max(0, Math.min(1, 1.0 - rawSum));
135	  return {
136	    enabled: true,
137	    signals,
138	    rawSum,
139	    score,
140	    floor: score === 0 || score === 1 ? "clamped" : "unclamped",
141	    floorExpression: "clamp(1.0 - Σ w·s, 0.0, 1.0)",
142	  };
143	}
