1	// Decision artifacts for each fixture DecisionInput. The artifact is built
2	// from the input + the gate-run-result. The artifact_hash is omitted from
3	// the canonicalized payload before hashing so the hash binds the input and
4	// outcome but not itself.
5	import type { DecisionInput, DecisionInputWithVariants, GateKey, GateRunResult, Regime } from "./decisionInputs";
6	import { DECISION_INPUTS } from "./decisionInputs";
7	
8	export interface DecisionArtifact {
9	  schema_version: 1;
10	  policy_version: "decision-policy-v1.0.0";
11	  parameter_set_id: "params-v1";
12	  input: DecisionInput;
13	  csReq: GateRunResult["csReq"];
14	  csObserved: number;
15	  outcome: "pass" | "fail" | "manual_review";
16	  failed_gates: GateKey[];
17	  reason_codes: string[];
18	  escalation_packet_ref: string | null;
19	  scoring_mode: "enforce" | "shadow";
20	  created_at_iso: string;
21	}
22	
23	export function buildArtifact(
24	  inputId: string,
25	  scoringMode: "enforce" | "shadow",
26	  regime: Regime,
27	): DecisionArtifact {
28	  const fixture = DECISION_INPUTS.find((d) => d.application_id === inputId) as DecisionInputWithVariants;
29	  const variant = fixture.regimeVariants[regime];
30	  const grr = variant.gateRunResult;
31	  // Strip the regimeVariants from the input snapshot (artifact captures the
32	  // applied input snapshot, not the precomputed alternatives).
33	  const inputSnapshot: DecisionInput = {
34	    application_id: fixture.application_id,
35	    founder_id: fixture.founder_id,
36	    requested_check_usd: fixture.requested_check_usd,
37	    domain_primary: fixture.domain_primary,
38	    domain_mix: fixture.domain_mix,
39	    coherence_superiority: fixture.coherence_superiority,
40	    coherence_superiority_ci95: fixture.coherence_superiority_ci95,
41	    transcript_quality_score: fixture.transcript_quality_score,
42	    transcript_quality_detail: fixture.transcript_quality_detail,
43	    anti_gaming_score: fixture.anti_gaming_score,
44	    compliance_status: fixture.compliance_status,
45	    portfolio_state: variant.portfolio_state,
46	    policy_version: fixture.policy_version,
47	  };
48	  const outcome = grr.overall === "pending" ? "pass" : (grr.overall as "pass" | "fail" | "manual_review");
49	  const failed: GateKey[] = grr.perGate.filter((g) => g.verdict === "fail" || g.verdict === "manual_review").map((g) => g.gate);
50	  const reasonCodes: string[] = grr.perGate.flatMap((g) => g.reasonCodes);
51	  return {
52	    schema_version: 1,
53	    policy_version: "decision-policy-v1.0.0",
54	    parameter_set_id: "params-v1",
55	    input: inputSnapshot,
56	    csReq: grr.csReq,
57	    csObserved: grr.csReq.csObserved,
58	    outcome,
59	    failed_gates: failed,
60	    reason_codes: reasonCodes,
61	    escalation_packet_ref: outcome === "pass" ? `esc-${inputId}` : null,
62	    scoring_mode: scoringMode,
63	    created_at_iso: "2026-04-18T10:14:22Z",
64	  };
65	}
